sql:
SELECT COUNT(*) AS total_confirmed_bookings
FROM bookings
WHERE booking_status = 'confirmed';

SELECT port_name
FROM embarkation_ports
WHERE country = 'USA';

SELECT cruise_name
FROM itineraries
WHERE itinerary_id = 1;

external_knowledge:
- Top three ports refer to the ports ranked 1, 2, and 3 according to the passenger count; 
- "most passengers" refers to the ports with the highest passenger count; 
- At least 50 passengers means the ports that have served a total of 50 or more passengers.

sql:
SELECT COUNT(*) AS total_bookings
FROM bookings
WHERE booking_status = 'confirmed' AND payment_status = 'paid';

SELECT COUNT(DISTINCT passenger_id) AS total_passengers
FROM bookings
WHERE itinerary_id = (SELECT itinerary_id FROM itineraries WHERE cruise_name = 'Caribbean Cruise');

external_knowledge:
- "Specific cruise" refers to a cruise with a unique identifier (itinerary_id = 1); 
- "Approved special requests" implies that the request_status is 'approved' in the special_requests table; 
- "Confirmed and fully paid bookings" means that the booking_status is 'confirmed' and payment_status is 'paid' in the bookings table.

sql:
SELECT COUNT(passenger_id)
FROM passengers
WHERE cabin IN (SELECT cabin_id FROM cabins WHERE cabin_type = 'Suite');
